+            dependency[$internal].relation ||
+            dependency[$internal].type === 'tag'
+        ) {
+            throw new Error('Koota: Predicate dependencies cannot be tags or relations.');
+        }
+    }
+
+    return Object.assign(createModifier('predicate', ++predicateId, dependencies), { predicate });
+}
+
+export function isPredicateModifier(modifier: unknown): modifier is PredicateModifier {
+    return typeof (modifier as PredicateModifier | undefined)?.predicate === 'function';
+}
